import Foundation

public actor ClaudeActiveAccountMonitor {
    // 15 s: short enough to react to account switches without hammering the disk.
    // Public so it can be referenced as a default argument value in callers' code.
    public static let defaultInterval: Duration = .seconds(15)

    private let claudeConfigPath: String
    private let fileManager: UsagesFileManager
    private let logger: FileLogger
    private let interval: Duration
    private let onActiveAccountChanged: (@Sendable (AccountEmail) async -> Void)?

    private var monitorTask: Task<Void, Never>?
    private var lastObservedActiveAccount: AccountEmail?

    private static let monitoredVendor: Vendor = .claude

    public init(
        claudeConfigPath: String? = nil,
        fileManager: UsagesFileManager,
        logger: FileLogger = Loggers.claude,
        interval: Duration = ClaudeActiveAccountMonitor.defaultInterval,
        onActiveAccountChanged: (@Sendable (AccountEmail) async -> Void)? = nil
    ) {
        let home = FileManager.default.homeDirectoryForCurrentUser.path
        self.claudeConfigPath = claudeConfigPath ?? "\(home)/.claude.json"
        self.fileManager = fileManager
        self.logger = logger
        self.interval = interval
        self.onActiveAccountChanged = onActiveAccountChanged
    }

    public func start() {
        guard monitorTask == nil else {
            logger.log(.warning, "Active-account monitor already running")
            return
        }
        logger.log(.info, "Starting active-account monitor with interval \(interval)")
        monitorTask = Task {
            while !Task.isCancelled {
                await self.checkOnce()
                try? await Task.sleep(for: self.interval)
                guard !Task.isCancelled else { break }
            }
        }
    }

    public func stop() {
        monitorTask?.cancel()
        monitorTask = nil
        logger.log(.info, "Active-account monitor stopped")
    }

    public func checkOnce() async {
        guard let active = readActiveAccount() else {
            // `/login` rewrites `.claude.json` through a transient state where `oauthAccount`
            // is absent (user briefly logged out between accounts). Treating that as "no active
            // account" would blank the menu bar label for up to one poll interval.
            // We only trust positive signals — preserve the previous isActive state otherwise.
            logger.log(.debug, "Active account unresolved — keeping previous isActive state")
            return
        }
        await fileManager.updateIsActive(vendor: Self.monitoredVendor, activeAccount: active)
        logger.log(.debug, "isActive updated: activeAccount=\(active.rawValue)")

        let previous = lastObservedActiveAccount
        lastObservedActiveAccount = active
        // Skip the callback on the first resolution (startup) — only fire on genuine switches,
        // so we don't force a redundant poll the first time the monitor sees an account.
        if let previous, previous != active {
            await onActiveAccountChanged?(active)
        }
    }

    private func readActiveAccount() -> AccountEmail? {
        guard let data = FileManager.default.contents(atPath: claudeConfigPath) else {
            logger.log(.warning, "Cannot read \(claudeConfigPath)")
            return nil
        }
        do {
            let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
            let oauth = json?["oauthAccount"] as? [String: Any]
            return (oauth?["emailAddress"] as? String).map(AccountEmail.init(rawValue:))
        } catch {
            logger.log(.error, "Failed to parse \(claudeConfigPath): \(error)")
            return nil
        }
    }
}

import Foundation

public actor ClaudeStatusConnector: StatusConnector {
    nonisolated public let vendor: Vendor = .claude

    private let logger: FileLogger
    private let session: URLSession
    private let endpointURLString: String

    private static let requestTimeoutSeconds: TimeInterval = 5
    public static let defaultEndpoint = "https://status.anthropic.com/api/v2/incidents/unresolved.json"

    public init(
        logger: FileLogger = Loggers.claude,
        session: URLSession = .shared,
        endpointURLString: String = ClaudeStatusConnector.defaultEndpoint
    ) {
        self.logger = logger
        self.session = session
        self.endpointURLString = endpointURLString
    }

    public func fetchOutages() async throws -> [Outage] {
        guard let url = URL(string: endpointURLString) else {
            throw StatusConnectorError.invalidURL(rawValue: endpointURLString)
        }
        var request = URLRequest(url: url)
        request.timeoutInterval = Self.requestTimeoutSeconds
        request.setValue("application/json", forHTTPHeaderField: "Accept")

        logger.log(.debug, "Fetching Claude status from \(endpointURLString)")

        let data: Data
        let response: URLResponse
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            logger.log(.warning, "Status endpoint network error: \(error)")
            throw StatusConnectorError.networkError(underlying: error, url: endpointURLString)
        }

        let httpCode = (response as? HTTPURLResponse)?.statusCode ?? -1
        guard httpCode == 200 else {
            logger.log(.warning, "Status endpoint returned HTTP \(httpCode)")
            throw StatusConnectorError.unexpectedResponse(statusCode: httpCode, url: endpointURLString)
        }

        let decoded: StatuspageIncidentsResponse
        do {
            decoded = try JSONDecoder().decode(StatuspageIncidentsResponse.self, from: data)
        } catch {
            logger.log(.error, "Status endpoint parse error: \(error)")
            throw StatusConnectorError.parseError(underlying: error, url: endpointURLString)
        }

        let outages: [Outage] = decoded.incidents.compactMap { incident in
            // "none" impact means the incident is informational with no user-facing effect —
            // don't surface it as an outage in the UI.
            guard incident.impact != "none" else { return nil }
            let severity = OutageSeverity(rawValue: incident.impact)
            // Invalid shortlink must not drop the incident itself — surface it without href.
            let href: URL?
            if let raw = incident.shortlink {
                href = URL(string: raw)
            } else {
                href = nil
            }
            return Outage(
                vendor: vendor,
                errorMessage: incident.name,
                severity: severity,
                since: ISODate(rawValue: incident.created_at),
                href: href
            )
        }
        logger.log(.info, "Claude status: \(outages.count) active outage(s)")
        return outages
    }

    // MARK: - DTOs

    private struct StatuspageIncidentsResponse: Decodable {
        let incidents: [StatuspageIncident]
    }

    private struct StatuspageIncident: Decodable {
        let name: String
        let impact: String
        let created_at: String
        let shortlink: String?
    }
}

# Swift concurrency safety

## Never block the cooperative thread pool

Swift concurrency uses a fixed-size thread pool. Blocking calls starve other tasks.

- **Never** call `Process.waitUntilExit()` or any synchronous blocking API from an `async` context or inside an `actor`. Wrap blocking work in a `DispatchQueue` or `Task.detached` with a continuation.
- **Never** call `readDataToEndOfFile()` *after* `waitUntilExit()` — this deadlocks when the pipe buffer is full. Always read pipes *before* waiting for process termination.

```swift
// BAD — blocks the cooperative thread pool
func run() async throws -> Data {
    process.launch()
    let data = pipe.fileHandleForReading.readDataToEndOfFile() // deadlock risk
    process.waitUntilExit() // blocks a cooperative thread
    return data
}

// GOOD — async with continuation, read before wait
func run() async throws -> Data {
    return try await withCheckedThrowingContinuation { continuation in
        DispatchQueue.global().async {
            process.launch()
            let data = pipe.fileHandleForReading.readDataToEndOfFile()
            process.waitUntilExit()
            continuation.resume(returning: data)
        }
    }
}
```

## NSFormatter and other non-thread-safe Foundation types

`DateFormatter`, `ISO8601DateFormatter`, `NumberFormatter`, and similar `NSFormatter` subclasses are **not thread-safe**. If used from concurrent contexts:

- Make them `static let` on a dedicated serial queue, OR
- Create a new instance each time (acceptable for cold paths), OR
- Use Swift's `nonisolated(unsafe)` only if you prove single-threaded access.

Never share a formatter across threads without synchronization.

```swift
// BAD — data race
actor MyActor {
    private let formatter = ISO8601DateFormatter()
    func format(_ date: Date) -> String {
        formatter.string(from: date) // races if called from nonisolated context
    }
}

// GOOD — one instance per call (simple, safe)
func format(_ date: Date) -> String {
    let formatter = ISO8601DateFormatter()
    return formatter.string(from: date)
}

// GOOD — static on serial queue (reusable, safe)
enum DateFormatting {
    private static let queue = DispatchQueue(label: "formatter")
    private static let formatter = ISO8601DateFormatter()
    static func format(_ date: Date) -> String {
        queue.sync { formatter.string(from: date) }
    }
}
```

## Do not use `weak self` inside actors

Actors are reference types with their own isolation. Using `[weak self]` in closures inside an actor is unnecessary and misleading — the actor manages its own lifetime. Use `[self]` or capture nothing.

## Always add a timeout when launching external processes

When spawning a `Process`, always set a timeout mechanism (e.g., `DispatchSource.makeTimerSource` or `Task.sleep` + cancellation). A hung child process must not hang the app forever.

# Swift error handling

## Never swallow errors with `try?` on fallible operations

Using `try?` silently discards the error. This is only acceptable for truly optional operations (e.g., deleting a cache file). For any operation whose failure affects correctness, use `try` with explicit error handling.

Critical operations that must NEVER use `try?`:
- `FileManager.createDirectory` — if it fails, all subsequent writes fail silently
- `FileManager.moveItem` / `copyItem` — rotation/backup failures mean data loss
- Network requests — silent failure means stale or missing data
- Keychain operations — silent failure means auth is broken

```swift
// BAD — silent failure, subsequent code assumes directory exists
try? FileManager.default.createDirectory(at: logsDir, withIntermediateDirectories: true)

// GOOD — propagate or handle explicitly
try FileManager.default.createDirectory(at: logsDir, withIntermediateDirectories: true)
```

## Never log success after a `catch` without `return`/`throw`

If a `catch` block logs an error but does not `return` or `throw`, execution falls through to subsequent code that may log success or assume the operation succeeded.

```swift
// BAD — logs "saved" even on failure
do {
    try save(data)
} catch {
    logger.error("save failed: \(error)")
}
logger.info("saved successfully") // reached on failure!

// GOOD — return in catch
do {
    try save(data)
    logger.info("saved successfully")
} catch {
    logger.error("save failed: \(error)")
    return
}
```

## Error types must carry diagnostic context

Custom error enums must include associated values with enough context to diagnose issues without access to logs.

```swift
// BAD — caller cannot distinguish causes or log details
enum ConnectorError: Error {
    case authenticationFailed
    case networkError
}

// GOOD — associated values carry context
enum ConnectorError: Error {
    case authenticationFailed(account: String, reason: String)
    case networkError(statusCode: Int, url: URL)
    case timeout(processPath: String, seconds: Int)
}
```

## Distinguish error causes precisely

When an operation can fail for multiple distinct reasons, create separate error cases. Do not conflate timeout, permission denial, and process failure into one case.

# Swift I/O robustness

## Atomic file writes

When writing data files (JSON, logs, config), always write to a temporary file first, then atomically rename. This prevents corruption if the process is killed mid-write.

```swift
// BAD — partial write on crash
try data.write(to: targetURL)

// GOOD — atomic rename
let tempURL = targetURL.appendingPathExtension("tmp")
try data.write(to: tempURL)
try FileManager.default.moveItem(at: tempURL, to: targetURL)

// ALSO GOOD — Foundation's built-in atomic option
try data.write(to: targetURL, options: .atomic)
```

## File locking: avoid TOCTOU and always set a timeout

When using `flock()` or any advisory lock:
- Never check-then-act (TOCTOU). Acquire the lock, then perform the operation, then release.
- Always set a timeout on lock acquisition. A hung process holding a lock must not block all future runs forever.
- Use `defer` to guarantee unlock.

```swift
// GOOD pattern
let fd = open(path, O_RDWR | O_CREAT, 0o644)
guard fd >= 0 else { throw IOError.cannotOpen(path) }
defer { close(fd) }

// Non-blocking attempt with retry + timeout
let deadline = Date().addingTimeInterval(5.0)
while flock(fd, LOCK_EX | LOCK_NB) != 0 {
    guard Date() < deadline else { throw IOError.lockTimeout(path) }
    try await Task.sleep(for: .milliseconds(50))
}
defer { flock(fd, LOCK_UN) }
```

## Efficient collection merges

When merging two collections by a key, use a dictionary for O(n+m) lookup instead of nested loops O(n*m).

```swift
// BAD — O(n*m)
for new in incoming {
    if let idx = existing.firstIndex(where: { $0.id == new.id }) {
        existing[idx] = new
    } else {
        existing.append(new)
    }
}

// GOOD — O(n+m)
var indexById = Dictionary(uniqueKeysWithValues: existing.enumerated().map { ($0.element.id, $0.offset) })
for item in incoming {
    if let idx = indexById[item.id] {
        existing[idx] = item
    } else {
        indexById[item.id] = existing.count
        existing.append(item)
    }
}
```

# Swift value objects

## Prefer value objects over primitive types for domain concepts

Representing domain concepts as plain `String` or `Int` makes APIs ambiguous and allows values to be accidentally swapped. Introduce a value object (a struct wrapping a primitive) whenever a field has a distinct identity or constrained meaning.

Typical candidates in this codebase:
- Email addresses, vendor names, ISO dates — wrap `String`
- Percentages, durations in a fixed unit — wrap `Int`
- Type discriminators with a closed set — use a `String` enum

```swift
// BAD — impossible to tell which String is which at the call site
func updateIsActive(vendor: String, activeAccount: String?) { ... }
updateIsActive(vendor: "claude", activeAccount: "user@example.com")

// GOOD — self-documenting, type-checked
func updateIsActive(vendor: Vendor, activeAccount: AccountEmail?) { ... }
updateIsActive(vendor: .claude, activeAccount: "user@example.com")
```

## Use a struct, not an enum, for open-ended string domains

Use a `struct` when new values can appear without a code change (e.g., vendor names, error codes). Name each known value as a `static let` constant. Unknown values decode transparently without throwing.

```swift
public struct Vendor: RawRepresentable, Codable, Equatable, Hashable, Sendable {
    public let rawValue: String
    public init(rawValue: String) { self.rawValue = rawValue }

    public static let claude = Vendor(rawValue: "claude")
}
```

Use a `enum` only when the set is closed and an unknown value must be a decode error (e.g., a JSON discriminator).

## Implement Codable manually — the default synthesis does not work for RawRepresentable structs

`JSONEncoder`/`JSONDecoder` do not synthesise `Codable` conformance for custom structs that are `RawRepresentable`. Implement the two methods explicitly:

```swift
public init(from decoder: Decoder) throws {
    rawValue = try decoder.singleValueContainer().decode(String.self)
}

public func encode(to encoder: Encoder) throws {
    var container = encoder.singleValueContainer()
    try container.encode(rawValue)
}
```

## Add ExpressibleByXxxLiteral for ergonomic call sites

String-based value objects should conform to `ExpressibleByStringLiteral`; integer-based ones to `ExpressibleByIntegerLiteral`. This keeps call sites and tests readable without sacrificing type safety.

```swift
extension AccountEmail: ExpressibleByStringLiteral {
    public init(stringLiteral value: String) { rawValue = value }
}

// Callers and tests look the same as before
let entry = VendorUsageEntry(vendor: "claude", account: "user@example.com")
dict["user@example.com"]  // subscript resolves to AccountEmail via ExpressibleByStringLiteral
```

Without this conformance, every call site needs an explicit `AccountEmail(rawValue: "...")` constructor — correct but noisy.

## Add CustomStringConvertible for clean logging

Value objects used in log messages should implement `CustomStringConvertible` and return `rawValue` as their description. Without this, string interpolation would print the struct's default representation (`Vendor(rawValue: "claude")` instead of `claude`).

```swift
extension Vendor: CustomStringConvertible {
    public var description: String { rawValue }
}
```

## Add domain behaviour as computed properties

When a value object stores a string that needs parsing (e.g., an ISO date), expose a computed property rather than requiring callers to parse it themselves. This centralises the parsing logic.

```swift
public struct ISODate: RawRepresentable, ... {
    public let rawValue: String

    /// Returns nil if the stored string is not a parseable ISO 8601 date.
    public var date: Date? {
        // New formatter per call — ISO8601DateFormatter is not thread-safe; acceptable for this cold path
        ISO8601DateFormatter().date(from: rawValue)
    }

    public init(date: Date) {
        // New formatter per call — acceptable for this cold path
        rawValue = ISO8601DateFormatter().string(from: date)
    }
}
```

Do not share a static `ISO8601DateFormatter` from inside a value-type method; value types have no isolation boundary. Creating one per call is thread-safe and acceptable for cold paths (see `docs/SWIFT-CONCURRENCY.md`).

## Add Comparable where ordering makes sense

For quantity wrappers (`UsagePercent`, `DurationMinutes`), add `Comparable` by delegating to `rawValue`. This enables `min`, `max`, `sort`, and `<` comparisons in business logic.

```swift
public static func < (lhs: UsagePercent, rhs: UsagePercent) -> Bool {
    lhs.rawValue < rhs.rawValue
}
```

## Value object checklist

When introducing a new domain field, ask:

| Question | If yes |
|---|---|
| Can two fields of this type be accidentally swapped? | Wrap in a value object |
| Can new values appear at runtime without a code change? | Use a `struct`, not an `enum` |
| Is the raw value compared frequently in tests? | Add `ExpressibleByXxxLiteral` |
| Is the value used in log messages? | Add `CustomStringConvertible` |
| Does the raw value need parsing into another type? | Add a computed property |
| Does ordering between values make sense? | Conform to `Comparable` |

# Swift testability and test coverage

## Design for dependency injection from the start

Every external dependency (network, file system, keychain, system clock, process execution) must be injectable via a protocol. This is non-negotiable for testability.

```swift
// BAD — hard-coded dependency, untestable
actor ClaudeConnector {
    func fetch() async throws -> Data {
        let (data, _) = try await URLSession.shared.data(from: url)
        return data
    }
}

// GOOD — injectable
protocol HTTPClient: Sendable {
    func data(from url: URL) async throws -> (Data, URLResponse)
}

extension URLSession: HTTPClient {}

actor ClaudeConnector {
    private let httpClient: HTTPClient
    init(httpClient: HTTPClient = URLSession.shared) {
        self.httpClient = httpClient
    }
}
```

Apply this to: `URLSession`, `Keychain` access, `FileManager`, `Process` execution, `Date()` / clock.

## Reuse expensive objects — do not instantiate per call

`ISO8601DateFormatter`, `JSONDecoder`, `JSONEncoder`, and similar heavyweight objects must be created once and reused. Do not instantiate them inside functions called repeatedly.

## Test every public method's primary path

When creating a new type, every public method must have at least one test covering the success path. In particular:
- Network-fetching methods (`fetchUsages`, `fetchToken`, etc.)
- File I/O methods (write, read, rotate, merge)
- Lifecycle methods (start/stop idempotence)
- Error paths for external failures (network down, disk full, lock contention)

## Force-unwrap only with compile-time-provable safety

Never force-unwrap (`!`) on runtime values. For URL literals that are known-valid at compile time, use a clearly documented pattern:

```swift
// Acceptable — string literal, provably valid
private static let apiBase = URL(string: "https://api.example.com")! // known-valid literal

// BAD — runtime input, may fail
let url = URL(string: userInput)! // crash on bad input
```

Even for literals, prefer a static `let` over inline force-unwrap to centralize the assumption.

## Comment WHY, not WHAT

Do not write comments that restate what the code does. Comments must explain *why* a non-obvious decision was made. If the code is self-explanatory, no comment is needed.

```swift
// BAD
// Create the directory
try FileManager.default.createDirectory(at: dir, withIntermediateDirectories: true)

// GOOD — no comment needed, the code is self-explanatory

// GOOD — explains a non-obvious choice
// Using LOCK_NB to avoid blocking the cooperative thread pool; retry with backoff instead.
while flock(fd, LOCK_EX | LOCK_NB) != 0 { ... }
```

## Name magic numbers

Every numeric literal (other than 0, 1, true, false) must be a named constant explaining its purpose.

```swift
// BAD
if fileSize > 5_242_880 { rotate() }

// GOOD
private static let maxLogFileSizeBytes = 5_242_880 // 5 MB
if fileSize > Self.maxLogFileSizeBytes { rotate() }
```

